     1→/**
     2→ * MMS Ingestion Service Tests
     3→ *
     4→ * Tests for CSV file processing, validation, anomaly detection,
     5→ * and meter event handling.
     6→ *
     7→ * Unit tests run without database. Integration tests require PostgreSQL.
     8→ *
     9→ * @see specs/004-domain-services.md Section 4.2
    10→ */
    11→
    12→import { describe, test, expect, beforeEach, afterEach, beforeAll } from 'bun:test';
    13→import * as fs from 'node:fs';
    14→import * as path from 'node:path';
    15→import { IngestionService } from './ingestion';
    16→import { db } from '../lib/db/connection';
    17→import { trains, mileageReadings, meterEvents, fleets, depots } from '../lib/db/schema';
    18→import { eq, sql } from 'drizzle-orm';
    19→
    20→// =============================================================================
    21→// Test Setup
    22→// =============================================================================
    23→
    24→const TEST_INBOX_PATH = '/tmp/mms-test-inbox';
    25→const TEST_PROCESSED_PATH = '/tmp/mms-test-processed';
    26→
    27→let service: IngestionService;
    28→let testDepotId: string;
    29→let testFleetId: string;
    30→let testTrainIds: string[] = [];
    31→let databaseAvailable = false;
    32→
    33→// Check if database is available
    34→async function checkDatabaseConnection(): Promise<boolean> {
    35→  try {
    36→    await db.execute(sql`SELECT 1`);
    37→    return true;
    38→  } catch {
    39→    return false;
    40→  }
    41→}
    42→
    43→// Create test directories and clean up
    44→function setupTestDirectories(): void {
    45→  [TEST_INBOX_PATH, TEST_PROCESSED_PATH].forEach((dir) => {
    46→    if (!fs.existsSync(dir)) {
    47→      fs.mkdirSync(dir, { recursive: true });
    48→    }
    49→  });
    50→}
    51→
    52→function cleanupTestDirectories(): void {
    53→  [TEST_INBOX_PATH, TEST_PROCESSED_PATH].forEach((dir) => {
    54→    if (fs.existsSync(dir)) {
    55→      fs.readdirSync(dir).forEach((file) => {
    56→        fs.unlinkSync(path.join(dir, file));
    57→      });
    58→    }
    59→  });
    60→}
    61→
    62→// Create a test CSV file
    63→function createTestCsv(
    64→  filename: string,
    65→  rows: Array<{ train_number: string; reading_date: string; odometer_km: number }>
    66→): string {
    67→  const header = 'train_number,reading_date,odometer_km';
    68→  const lines = rows.map((r) => `${r.train_number},${r.reading_date},${r.odometer_km}`);
    69→  const content = [header, ...lines].join('\n');
    70→
    71→  const filePath = path.join(TEST_INBOX_PATH, filename);
    72→  fs.writeFileSync(filePath, content);
    73→
    74→  return filePath;
    75→}
    76→
    77→// Create test data in database
    78→async function setupTestData(): Promise<void> {
    79→  if (!databaseAvailable) return;
    80→
    81→  // Create test depot
    82→  const [depot] = await db.insert(depots).values({
    83→    code: 'TEST-DEPOT',
    84→    name: 'Test Depot',
    85→    timezone: 'UTC',
    86→  }).returning();
    87→  testDepotId = depot.id;
    88→
    89→  // Create test fleet
    90→  const [fleet] = await db.insert(fleets).values({
    91→    code: 'TEST-FLEET',
    92→    name: 'Test Fleet',
    93→    manufacturer: 'Test Manufacturer',
    94→    carsPerTrain: 4,
    95→    baseDepotId: testDepotId,
    96→  }).returning();
    97→  testFleetId = fleet.id;
    98→
    99→  // Create test trains
   100→  for (let i = 1; i <= 3; i++) {
   101→    const [train] = await db.insert(trains).values({
   102→      trainNumber: `T00${i}`,
   103→      fleetId: testFleetId,
   104→      currentMileageKm: 100000 + (i * 10000),
   105→      fitnessStatus: 'FIT',
   106→      currentDepotId: testDepotId,
   107→      homeDepotId: testDepotId,
   108→    }).returning();
   109→    testTrainIds.push(train.id);
   110→  }
   111→}
   112→
   113→// Clean up test data
   114→async function cleanupTestData(): Promise<void> {
   115→  if (!databaseAvailable) return;
   116→
   117→  // Delete in reverse order of dependencies
   118→  if (testTrainIds.length > 0) {
   119→    await db.delete(mileageReadings).where(
   120→      sql`${mileageReadings.trainId} = ANY(${testTrainIds}::uuid[])`
   121→    );
   122→    await db.delete(meterEvents).where(
   123→      sql`${meterEvents.trainId} = ANY(${testTrainIds}::uuid[])`
   124→    );
   125→    await db.delete(trains).where(
   126→      sql`${trains.id} = ANY(${testTrainIds}::uuid[])`
   127→    );
   128→  }
   129→
   130→  if (testFleetId) {
   131→    await db.delete(fleets).where(eq(fleets.id, testFleetId));
   132→  }
   133→
   134→  if (testDepotId) {
   135→    await db.delete(depots).where(eq(depots.id, testDepotId));
   136→  }
   137→
   138→  testTrainIds = [];
   139→}
