   141→// =============================================================================
   142→// Unit Tests (No Database Required)
   143→// =============================================================================
   144→
   145→describe('IngestionService', () => {
   146→  beforeAll(async () => {
   147→    databaseAvailable = await checkDatabaseConnection();
   148→    if (!databaseAvailable) {
   149→      console.log('Database not available - skipping integration tests');
   150→    }
   151→  });
   152→
   153→  beforeEach(() => {
   154→    service = new IngestionService();
   155→    setupTestDirectories();
   156→  });
   157→
   158→  afterEach(() => {
   159→    cleanupTestDirectories();
   160→  });
   161→
   162→  describe('File Validation (Unit Tests)', () => {
   163→    test('should reject non-existent file', async () => {
   164→      const result = await service.validateFile('/non/existent/file.csv');
   165→
   166→      expect(result.valid).toBe(false);
   167→      expect(result.errors).toContain('File not found: /non/existent/file.csv');
   168→    });
   169→
   170→    test('should reject empty file', async () => {
   171→      const filePath = path.join(TEST_INBOX_PATH, 'empty.csv');
   172→      fs.writeFileSync(filePath, '');
   173→
   174→      const result = await service.validateFile(filePath);
   175→
   176→      expect(result.valid).toBe(false);
   177→      expect(result.errors.some((e) => e.includes('empty'))).toBe(true);
   178→    });
   179→
   180→    test('should warn on incorrect filename pattern', async () => {
   181→      const filePath = path.join(TEST_INBOX_PATH, 'wrong_name.csv');
   182→      fs.writeFileSync(filePath, 'train_number,reading_date,odometer_km\nT001,2024-01-15,100000');
   183→
   184→      const result = await service.validateFile(filePath);
   185→
   186→      expect(result.warnings.some((w) => w.includes('expected pattern'))).toBe(true);
   187→    });
   188→
   189→    test('should reject file with missing required columns', async () => {
   190→      const filePath = path.join(TEST_INBOX_PATH, 'missing_columns.csv');
   191→      fs.writeFileSync(filePath, 'train_number,date\nT001,2024-01-15');
   192→
   193→      const result = await service.validateFile(filePath);
   194→
   195→      expect(result.valid).toBe(false);
   196→      expect(result.errors.some((e) => e.includes('Missing required column'))).toBe(true);
   197→    });
   198→
   199→    test('should accept valid CSV file', async () => {
   200→      const filePath = path.join(TEST_INBOX_PATH, 'mileage_20240115.csv');
   201→      fs.writeFileSync(filePath, 'train_number,reading_date,odometer_km\nT001,2024-01-15,100000');
   202→
   203→      const result = await service.validateFile(filePath);
   204→
   205→      expect(result.valid).toBe(true);
   206→      expect(result.errors.length).toBe(0);
   207→    });
   208→
   209→    test('should accept valid CSV file with multiple columns', async () => {
   210→      const filePath = path.join(TEST_INBOX_PATH, 'mileage_20240115.csv');
   211→      fs.writeFileSync(
   212→        filePath,
   213→        'train_number,reading_date,odometer_km,extra_col\nT001,2024-01-15,100000,value'
   214→      );
   215→
   216→      const result = await service.validateFile(filePath);
   217→
   218→      expect(result.valid).toBe(true);
   219→    });
   220→  });
   221→
   222→  describe('Health Monitoring (Unit Tests)', () => {
   223→    test('should report healthy when no files received yet', async () => {
   224→      const health = await service.checkFileArrivalHealth();
   225→
   226→      expect(health.healthy).toBe(true);
   227→      expect(health.lastFileAt).toBeNull();
   228→    });
   229→  });
   230→});
