   571→  describe('Result Status Determination', () => {
   572→    test('should return SUCCESS when all records valid', async () => {
   573→      if (!databaseAvailable) {
   574→        console.log('Skipping: Database not available');
   575→        return;
   576→      }
   577→
   578→      await setupTestData();
   579→
   580→      const filePath = createTestCsv('mileage_20240115.csv', [
   581→        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
   582→      ]);
   583→
   584→      const result = await service.processFile(filePath, 'test-job-15');
   585→
   586→      expect(result.status).toBe('SUCCESS');
   587→    });
   588→
   589→    test('should return PARTIAL when some records invalid', async () => {
   590→      if (!databaseAvailable) {
   591→        console.log('Skipping: Database not available');
   592→        return;
   593→      }
   594→
   595→      await setupTestData();
   596→
   597→      const filePath = createTestCsv('mileage_20240115.csv', [
   598→        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
   599→        { train_number: 'UNKNOWN', reading_date: '2024-01-15', odometer_km: 999999 },
