/**
 * MMS Ingestion Service Tests
 *
 * Tests for CSV file processing, validation, anomaly detection,
 * and meter event handling.
 *
 * Unit tests run without database. Integration tests require PostgreSQL.
 *
 * @see specs/004-domain-services.md Section 4.2
 */

import { describe, test, expect, beforeEach, afterEach, beforeAll } from 'bun:test';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { IngestionService } from './ingestion';
import { db } from '../lib/db/connection';
import { trains, mileageReadings, meterEvents, fleets, depots } from '../lib/db/schema';
import { eq, sql } from 'drizzle-orm';

// =============================================================================
// Test Setup
// =============================================================================

const TEST_INBOX_PATH = '/tmp/mms-test-inbox';
const TEST_PROCESSED_PATH = '/tmp/mms-test-processed';

let service: IngestionService;
let testDepotId: string;
let testFleetId: string;
let testTrainIds: string[] = [];
let databaseAvailable = false;

// Check if database is available
async function checkDatabaseConnection(): Promise<boolean> {
  try {
    await db.execute(sql`SELECT 1`);
    return true;
  } catch {
    return false;
  }
}

// Create test directories and clean up
function setupTestDirectories(): void {
  [TEST_INBOX_PATH, TEST_PROCESSED_PATH].forEach((dir) => {
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
  });
}

function cleanupTestDirectories(): void {
  [TEST_INBOX_PATH, TEST_PROCESSED_PATH].forEach((dir) => {
    if (fs.existsSync(dir)) {
      fs.readdirSync(dir).forEach((file) => {
        fs.unlinkSync(path.join(dir, file));
      });
    }
  });
}

// Create a test CSV file
function createTestCsv(
  filename: string,
  rows: Array<{ train_number: string; reading_date: string; odometer_km: number }>
): string {
  const header = 'train_number,reading_date,odometer_km';
  const lines = rows.map((r) => `${r.train_number},${r.reading_date},${r.odometer_km}`);
  const content = [header, ...lines].join('\n');

  const filePath = path.join(TEST_INBOX_PATH, filename);
  fs.writeFileSync(filePath, content);

  return filePath;
}

// Create test data in database
async function setupTestData(): Promise<void> {
  if (!databaseAvailable) return;

  // Create test depot
  const [depot] = await db.insert(depots).values({
    code: 'TEST-DEPOT',
    name: 'Test Depot',
    timezone: 'UTC',
  }).returning();
  testDepotId = depot.id;

  // Create test fleet
  const [fleet] = await db.insert(fleets).values({
    code: 'TEST-FLEET',
    name: 'Test Fleet',
    manufacturer: 'Test Manufacturer',
    carsPerTrain: 4,
    baseDepotId: testDepotId,
  }).returning();
  testFleetId = fleet.id;

  // Create test trains
  for (let i = 1; i <= 3; i++) {
    const [train] = await db.insert(trains).values({
      trainNumber: `T00${i}`,
      fleetId: testFleetId,
      currentMileageKm: 100000 + (i * 10000),
      fitnessStatus: 'FIT',
      currentDepotId: testDepotId,
      homeDepotId: testDepotId,
    }).returning();
    testTrainIds.push(train.id);
  }
}

// Clean up test data
async function cleanupTestData(): Promise<void> {
  if (!databaseAvailable) return;

  // Delete in reverse order of dependencies
  if (testTrainIds.length > 0) {
    await db.delete(mileageReadings).where(
      sql`${mileageReadings.trainId} = ANY(${testTrainIds}::uuid[])`
    );
    await db.delete(meterEvents).where(
      sql`${meterEvents.trainId} = ANY(${testTrainIds}::uuid[])`
    );
    await db.delete(trains).where(
      sql`${trains.id} = ANY(${testTrainIds}::uuid[])`
    );
  }

  if (testFleetId) {
    await db.delete(fleets).where(eq(fleets.id, testFleetId));
  }

  if (testDepotId) {
    await db.delete(depots).where(eq(depots.id, testDepotId));
  }

  testTrainIds = [];
}

// =============================================================================
// Unit Tests (No Database Required)
// =============================================================================

describe('IngestionService', () => {
  beforeAll(async () => {
    databaseAvailable = await checkDatabaseConnection();
    if (!databaseAvailable) {
      console.log('Database not available - skipping integration tests');
    }
  });

  beforeEach(() => {
    service = new IngestionService();
    setupTestDirectories();
  });

  afterEach(() => {
    cleanupTestDirectories();
  });

  describe('File Validation (Unit Tests)', () => {
    test('should reject non-existent file', async () => {
      const result = await service.validateFile('/non/existent/file.csv');

      expect(result.valid).toBe(false);
      expect(result.errors).toContain('File not found: /non/existent/file.csv');
    });

    test('should reject empty file', async () => {
      const filePath = path.join(TEST_INBOX_PATH, 'empty.csv');
      fs.writeFileSync(filePath, '');

      const result = await service.validateFile(filePath);

      expect(result.valid).toBe(false);
      expect(result.errors.some((e) => e.includes('empty'))).toBe(true);
    });

    test('should warn on incorrect filename pattern', async () => {
      const filePath = path.join(TEST_INBOX_PATH, 'wrong_name.csv');
      fs.writeFileSync(filePath, 'train_number,reading_date,odometer_km\nT001,2024-01-15,100000');

      const result = await service.validateFile(filePath);

      expect(result.warnings.some((w) => w.includes('expected pattern'))).toBe(true);
    });

    test('should reject file with missing required columns', async () => {
      const filePath = path.join(TEST_INBOX_PATH, 'missing_columns.csv');
      fs.writeFileSync(filePath, 'train_number,date\nT001,2024-01-15');

      const result = await service.validateFile(filePath);

      expect(result.valid).toBe(false);
      expect(result.errors.some((e) => e.includes('Missing required column'))).toBe(true);
    });

    test('should accept valid CSV file', async () => {
      const filePath = path.join(TEST_INBOX_PATH, 'mileage_20240115.csv');
      fs.writeFileSync(filePath, 'train_number,reading_date,odometer_km\nT001,2024-01-15,100000');

      const result = await service.validateFile(filePath);

      expect(result.valid).toBe(true);
      expect(result.errors.length).toBe(0);
    });

    test('should accept valid CSV file with multiple columns', async () => {
      const filePath = path.join(TEST_INBOX_PATH, 'mileage_20240115.csv');
      fs.writeFileSync(
        filePath,
        'train_number,reading_date,odometer_km,extra_col\nT001,2024-01-15,100000,value'
      );

      const result = await service.validateFile(filePath);

      expect(result.valid).toBe(true);
    });
  });

  describe('Health Monitoring (Unit Tests)', () => {
    test('should report healthy when no files received yet', async () => {
      const health = await service.checkFileArrivalHealth();

      expect(health.healthy).toBe(true);
      expect(health.lastFileAt).toBeNull();
    });
  });
});

// =============================================================================
// Integration Tests (Database Required)
// =============================================================================

describe('IngestionService Integration Tests', () => {
  beforeAll(async () => {
    databaseAvailable = await checkDatabaseConnection();
  });

  beforeEach(async () => {
    if (!databaseAvailable) return;

    service = new IngestionService();
    setupTestDirectories();
  });

  afterEach(async () => {
    cleanupTestDirectories();
    await cleanupTestData();
  });

  describe('CSV Parsing', () => {
    test('should parse valid CSV rows', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
        { train_number: 'T002', reading_date: '2024-01-15', odometer_km: 110500 },
      ]);

      const result = await service.processFile(filePath, 'test-job-1');

      expect(result.totalRecords).toBe(2);
      expect(result.validRecords).toBe(2);
      expect(result.invalidRecords).toBe(0);
      expect(result.status).toBe('SUCCESS');
    });

    test('should handle unknown train numbers', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
        { train_number: 'UNKNOWN', reading_date: '2024-01-15', odometer_km: 999999 },
      ]);

      const result = await service.processFile(filePath, 'test-job-2');

      expect(result.totalRecords).toBe(2);
      expect(result.validRecords).toBe(1);
      expect(result.invalidRecords).toBe(1);
      expect(result.anomalies.some((a) => a.type === 'UNKNOWN_TRAIN')).toBe(true);
      expect(result.status).toBe('PARTIAL');
    });
  });

  describe('Anomaly Detection', () => {
    test('should detect negative daily mileage', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      // First, insert a baseline reading
      await db.insert(mileageReadings).values({
        trainId: testTrainIds[0]!,
        readingDate: '2024-01-14',
        rawReading: 100000,
        adjustedReading: 100000,
        dailyKm: 300,
        validationStatus: 'VALID',
        sourceFile: 'test.csv',
      });

      // Now process a file with lower mileage
      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 99500 },
      ]);

      const result = await service.processFile(filePath, 'test-job-4');

      expect(result.anomalies.length).toBeGreaterThan(0);
      expect(result.anomalies.some((a) => a.type === 'NEGATIVE')).toBe(true);
    });

    test('should detect spike in daily mileage', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      // First, insert a baseline reading
      await db.insert(mileageReadings).values({
        trainId: testTrainIds[0]!,
        readingDate: '2024-01-14',
        rawReading: 100000,
        adjustedReading: 100000,
        dailyKm: 300,
        validationStatus: 'VALID',
        sourceFile: 'test.csv',
      });

      // Now process a file with spike (>1000km daily)
      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 101500 },
      ]);

      const result = await service.processFile(filePath, 'test-job-5');

      expect(result.anomalies.length).toBeGreaterThan(0);
      expect(result.anomalies.some((a) => a.type === 'SPIKE')).toBe(true);
    });
  });

  describe('Mileage Reading Updates', () => {
    test('should insert new mileage readings', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
      ]);

      await service.processFile(filePath, 'test-job-7');

      // Verify reading was inserted
      const readings = await db.query.mileageReadings.findMany({
        where: eq(mileageReadings.trainId, testTrainIds[0]!),
      });

      expect(readings.length).toBe(1);
      expect(readings[0]!.rawReading).toBe(100500);
      expect(readings[0]!.adjustedReading).toBe(100500);
    });

    test('should update existing mileage reading on duplicate', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      // Insert first reading
      const filePath1 = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
      ]);
      await service.processFile(filePath1, 'test-job-8a');

      // Update with corrected value
      const filePath2 = createTestCsv('mileage_20240115_v2.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100600 },
      ]);
      await service.processFile(filePath2, 'test-job-8b');

      // Verify reading was updated (not duplicated)
      const readings = await db.query.mileageReadings.findMany({
        where: eq(mileageReadings.trainId, testTrainIds[0]!),
      });

      expect(readings.length).toBe(1);
      expect(readings[0]!.rawReading).toBe(100600);
    });

    test('should update train current mileage', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 150000 },
      ]);

      await service.processFile(filePath, 'test-job-9');

      // Verify train mileage was updated
      const train = await db.query.trains.findFirst({
        where: eq(trains.id, testTrainIds[0]!),
      });

      expect(train!.currentMileageKm).toBe(150000);
    });
  });

  describe('Meter Events', () => {
    test('should create meter event', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const result = await service.createMeterEvent(
        testTrainIds[0]!,
        'RESET',
        '2024-01-15',
        100000,
        0,
        'Meter replacement after maintenance',
        undefined
      );

      expect(result.trainNumber).toBe('T001');
      expect(result.eventType).toBe('RESET');
      expect(result.adjustmentKm).toBe(100000); // old - new = 100000 - 0

      // Verify event was stored
      const events = await service.getMeterEvents(testTrainIds[0]!);
      expect(events.length).toBe(1);
      expect(events[0]!.adjustmentKm).toBe(100000);
    });

    test('should apply meter adjustment to readings', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      // Create meter event (meter reset from 100000 to 0)
      await service.createMeterEvent(
        testTrainIds[0]!,
        'RESET',
        '2024-01-14',
        100000,
        0,
        'Meter reset'
      );

      // Insert reading after reset
      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 300 },
      ]);

      await service.processFile(filePath, 'test-job-10');

      // Verify adjusted reading accounts for meter event
      const readings = await db.query.mileageReadings.findMany({
        where: eq(mileageReadings.trainId, testTrainIds[0]!),
      });

      expect(readings.length).toBe(1);
      expect(readings[0]!.rawReading).toBe(300);
      expect(readings[0]!.adjustedReading).toBe(100300); // 300 + 100000 adjustment
    });
  });

  describe('Batch Processing', () => {
    test('should process multiple trains in batch', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
        { train_number: 'T002', reading_date: '2024-01-15', odometer_km: 110500 },
        { train_number: 'T003', reading_date: '2024-01-15', odometer_km: 120500 },
      ]);

      const result = await service.processFile(filePath, 'test-job-11');

      expect(result.totalRecords).toBe(3);
      expect(result.validRecords).toBe(3);
      expect(result.trainsUpdated).toBe(3);
      expect(result.status).toBe('SUCCESS');
    });

    test('should continue processing after individual record failure', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
        { train_number: 'UNKNOWN', reading_date: '2024-01-15', odometer_km: 999999 },
        { train_number: 'T002', reading_date: '2024-01-15', odometer_km: 110500 },
      ]);

      const result = await service.processFile(filePath, 'test-job-12');

      expect(result.totalRecords).toBe(3);
      expect(result.validRecords).toBe(2);
      expect(result.invalidRecords).toBe(1);
      expect(result.status).toBe('PARTIAL');
    });
  });

  describe('Statistics', () => {
    test('should return ingestion statistics', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      // Process a file first
      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
      ]);
      await service.processFile(filePath, 'test-job-14');

      const stats = await service.getIngestionStats(7);

      expect(stats.totalRecords).toBeGreaterThanOrEqual(1);
      expect(typeof stats.totalFiles).toBe('number');
      expect(typeof stats.averageRecordsPerFile).toBe('number');
    });
  });

  describe('Result Status Determination', () => {
    test('should return SUCCESS when all records valid', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
      ]);

      const result = await service.processFile(filePath, 'test-job-15');

      expect(result.status).toBe('SUCCESS');
    });

    test('should return PARTIAL when some records invalid', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'T001', reading_date: '2024-01-15', odometer_km: 100500 },
        { train_number: 'UNKNOWN', reading_date: '2024-01-15', odometer_km: 999999 },
      ]);

      const result = await service.processFile(filePath, 'test-job-16');

      expect(result.status).toBe('PARTIAL');
    });

    test('should return FAILED when all records invalid', async () => {
      if (!databaseAvailable) {
        console.log('Skipping: Database not available');
        return;
      }

      await setupTestData();

      const filePath = createTestCsv('mileage_20240115.csv', [
        { train_number: 'UNKNOWN1', reading_date: '2024-01-15', odometer_km: 100000 },
        { train_number: 'UNKNOWN2', reading_date: '2024-01-15', odometer_km: 200000 },
      ]);

      const result = await service.processFile(filePath, 'test-job-17');

      expect(result.status).toBe('FAILED');
    });
  });
});

