    48→
    49→  describe('Day Type Calculation', () => {
    50→    test('should identify weekdays correctly', () => {
    51→      const service = new RouteUtilizationService();
    52→
    53→      // Monday (2026-01-19 is a Monday)
    54→      expect(service.getDayType('2026-01-19')).toBe('WEEKDAY');
    55→      // Tuesday
    56→      expect(service.getDayType('2026-01-20')).toBe('WEEKDAY');
    57→      // Wednesday
    58→      expect(service.getDayType('2026-01-21')).toBe('WEEKDAY');
    59→      // Thursday
    60→      expect(service.getDayType('2026-01-22')).toBe('WEEKDAY');
    61→      // Friday
    62→      expect(service.getDayType('2026-01-23')).toBe('WEEKDAY');
    63→    });
    64→
    65→    test('should identify Saturday correctly', () => {
    66→      const service = new RouteUtilizationService();
    67→      // 2026-01-24 is Saturday
    68→      expect(service.getDayType('2026-01-24')).toBe('SATURDAY');
    69→    });
    70→
    71→    test('should identify Sunday correctly', () => {
    72→      const service = new RouteUtilizationService();
    73→      // 2026-01-25 is Sunday
    74→      expect(service.getDayType('2026-01-25')).toBe('SUNDAY');
    75→    });
    76→
    77→    test('should identify holidays from provided list', () => {
    78→      const service = new RouteUtilizationService();
    79→      const holidays = ['2026-01-01', '2026-01-26', '2026-12-25'];
    80→
    81→      // Jan 1 is a holiday (would be Thursday)
    82→      expect(service.getDayType('2026-01-01', holidays)).toBe('HOLIDAY');
    83→
    84→      // Jan 26 is a holiday (would be Monday)
    85→      expect(service.getDayType('2026-01-26', holidays)).toBe('HOLIDAY');
    86→
    87→      // Dec 25 is a holiday
    88→      expect(service.getDayType('2026-12-25', holidays)).toBe('HOLIDAY');
    89→    });
    90→
    91→    test('should return weekday for non-holiday weekday dates', () => {
    92→      const service = new RouteUtilizationService();
    93→      const holidays = ['2026-01-01'];
    94→
    95→      // Jan 2 is not a holiday
    96→      expect(service.getDayType('2026-01-02', holidays)).toBe('WEEKDAY');
    97→    });
    98→  });
