/**
 * MMS Unavailability Service Unit Tests
 *
 * Tests for the Unavailability Service covering:
 * - Event creation with train fitness sync
 * - Event resolution and fitness restoration
 * - Active events queries for optimizer
 * - PM conflict detection
 * - Maximo integration helpers
 *
 * @see src/services/unavailability.ts
 */

import { describe, test, expect } from 'bun:test';
import {
  UnavailabilityService,
  type CreateEventRequest,
  type ResolveEventRequest,
  type EventListFilters,
  type PMConflict,
  type OptimizerConstraints,
} from './unavailability';
import {
  NotFoundError,
  TrainNotFoundError,
  BusinessRuleError,
  ConflictError,
} from '../lib/errors';

// Note: These tests document the expected behavior and serve as a specification.
// Integration tests with actual database should be in a separate test suite.

describe('UnavailabilityService', () => {
  describe('Initialization', () => {
    test('should create an UnavailabilityService instance', () => {
      const service = new UnavailabilityService();
      expect(service).toBeDefined();
      expect(service).toBeInstanceOf(UnavailabilityService);
    });
  });

  describe('Type Definitions', () => {
    describe('CreateEventRequest', () => {
      test('should support all event types', () => {
        const eventTypes = [
          'CORRECTIVE',
          'INCIDENT',
          'COLLISION',
          'VANDALISM',
          'EXTERNAL',
          'PLANNED_OUTAGE',
        ] as const;

        for (const eventType of eventTypes) {
          const request: CreateEventRequest = {
            trainId: 'train-123',
            eventType,
            restrictionLevel: 'GROUNDED',
          };
          expect(request.eventType).toBe(eventType);
        }
      });

      test('should support both restriction levels', () => {
        const restrictedRequest: CreateEventRequest = {
          trainId: 'train-123',
          eventType: 'CORRECTIVE',
          restrictionLevel: 'RESTRICTED',
        };
        expect(restrictedRequest.restrictionLevel).toBe('RESTRICTED');

        const groundedRequest: CreateEventRequest = {
          trainId: 'train-123',
          eventType: 'CORRECTIVE',
          restrictionLevel: 'GROUNDED',
        };
        expect(groundedRequest.restrictionLevel).toBe('GROUNDED');
      });

      test('should support Maximo integration fields', () => {
        const request: CreateEventRequest = {
          trainId: 'train-123',
          eventType: 'CORRECTIVE',
          restrictionLevel: 'GROUNDED',
          sourceSystem: 'MAXIMO',
          externalReference: 'WO-2026-001234',
          externalStatus: 'INPRG',
        };
        expect(request.sourceSystem).toBe('MAXIMO');
        expect(request.externalReference).toBe('WO-2026-001234');
      });

      test('should support optional fields', () => {
        const request: CreateEventRequest = {
          trainId: 'train-123',
          eventType: 'CORRECTIVE',
          restrictionLevel: 'GROUNDED',
          description: 'Traction motor failure',
          failureCode: 'TM-001',
          affectedSystem: 'TRACTION',
          estimatedRepairHours: 24,
          estimatedReturnDate: '2026-01-25',
          blocksPmScheduling: true,
          blocksRunAssignment: true,
        };
        expect(request.description).toBe('Traction motor failure');
        expect(request.failureCode).toBe('TM-001');
        expect(request.affectedSystem).toBe('TRACTION');
      });
    });

    describe('ResolveEventRequest', () => {
      test('should require event ID and actual return date', () => {
        const request: ResolveEventRequest = {
          eventId: 'event-123',
          actualReturnDate: '2026-01-25',
        };
        expect(request.eventId).toBe('event-123');
        expect(request.actualReturnDate).toBe('2026-01-25');
      });

      test('should support resolution notes', () => {
        const request: ResolveEventRequest = {
          eventId: 'event-123',
          actualReturnDate: '2026-01-25',
          resolutionNotes: 'Motor replaced, train tested and cleared',
          resolvedBy: 'user-456',
        };
        expect(request.resolutionNotes).toBe('Motor replaced, train tested and cleared');
      });
    });

    describe('EventListFilters', () => {
      test('should support all filter options', () => {
        const filters: EventListFilters = {
          trainId: 'train-123',
          status: 'ACTIVE',
          eventType: 'CORRECTIVE',
          restrictionLevel: 'GROUNDED',
          sourceSystem: 'MAXIMO',
          dateFrom: '2026-01-01',
          dateTo: '2026-01-31',
          blocksPmScheduling: true,
          blocksRunAssignment: true,
        };
        expect(filters.status).toBe('ACTIVE');
        expect(filters.eventType).toBe('CORRECTIVE');
      });

      test('should support multiple train IDs', () => {
        const filters: EventListFilters = {
          trainIds: ['train-1', 'train-2', 'train-3'],
        };
        expect(filters.trainIds).toHaveLength(3);
      });

      test('should support array of event types', () => {
        const filters: EventListFilters = {
          eventType: ['CORRECTIVE', 'INCIDENT', 'COLLISION'],
        };
        expect(Array.isArray(filters.eventType)).toBe(true);
      });
    });

    describe('OptimizerConstraints', () => {
      test('should have correct structure', () => {
        const constraints: OptimizerConstraints = {
          groundedTrainIds: ['train-1', 'train-2'],
          restrictedTrainIds: ['train-3'],
          blockedFromPmTrainIds: ['train-1', 'train-2', 'train-3'],
          blockedFromRunAssignmentTrainIds: ['train-1', 'train-2'],
          totalActiveEvents: 5,
        };
        expect(constraints.groundedTrainIds).toHaveLength(2);
        expect(constraints.restrictedTrainIds).toHaveLength(1);
        expect(constraints.totalActiveEvents).toBe(5);
      });
    });

    describe('PMConflict', () => {
      test('should have correct severity levels', () => {
        const highConflict: PMConflict = {
          pmScheduleId: 'pm-1',
          trainId: 'train-1',
          trainNumber: 'T001',
          pmCode: 'C4',
          targetDate: '2026-01-25',
          unavailabilityEventId: 'event-1',
          eventType: 'CORRECTIVE',
          estimatedReturnDate: '2026-02-01',
          severity: 'HIGH',
          message: 'PM scheduled during unavailability',
        };
        expect(highConflict.severity).toBe('HIGH');

        const mediumConflict: PMConflict = {
          ...highConflict,
          severity: 'MEDIUM',
        };
        expect(mediumConflict.severity).toBe('MEDIUM');
      });
    });
  });

  describe('Business Rules', () => {
    describe('Fitness Status Sync', () => {
      test('ACTIVE event should update train to restriction level', () => {
        // When an event is created:
        // - Event status = ACTIVE
        // - Train fitness = restrictionLevel (RESTRICTED or GROUNDED)
        const eventRestrictionLevel = 'GROUNDED';
        const expectedTrainFitness = eventRestrictionLevel;
        expect(expectedTrainFitness).toBe('GROUNDED');
      });

      test('RESOLVED event should restore train to FIT if no other events', () => {
        // When last event is resolved:
        // - Event status = RESOLVED
        // - Train fitness = FIT
        const otherActiveEvents: unknown[] = [];
        const expectedTrainFitness = otherActiveEvents.length === 0 ? 'FIT' : 'RESTRICTED';
        expect(expectedTrainFitness).toBe('FIT');
      });

      test('RESOLVED event should keep train RESTRICTED if other events exist', () => {
        // When event is resolved but others remain:
        // - Train fitness = most restrictive of remaining
        const otherActiveEvents = [
          { restrictionLevel: 'RESTRICTED' },
          { restrictionLevel: 'RESTRICTED' },
        ];
        const hasGrounded = otherActiveEvents.some((e) => e.restrictionLevel === 'GROUNDED');
        const expectedTrainFitness = hasGrounded ? 'GROUNDED' : 'RESTRICTED';
        expect(expectedTrainFitness).toBe('RESTRICTED');
      });

      test('RESOLVED event should keep train GROUNDED if grounded event remains', () => {
        const otherActiveEvents = [
          { restrictionLevel: 'RESTRICTED' },
          { restrictionLevel: 'GROUNDED' },
        ];
        const hasGrounded = otherActiveEvents.some((e) => e.restrictionLevel === 'GROUNDED');
        const expectedTrainFitness = hasGrounded ? 'GROUNDED' : 'RESTRICTED';
        expect(expectedTrainFitness).toBe('GROUNDED');
      });
    });

    describe('PM Blocking Rules', () => {
      test('blocksPmScheduling=true should prevent PM scheduling', () => {
        const event = { blocksPmScheduling: true };
        expect(event.blocksPmScheduling).toBe(true);
      });

      test('blocksRunAssignment=true should prevent run assignment', () => {
        const event = { blocksRunAssignment: true };
        expect(event.blocksRunAssignment).toBe(true);
      });

      test('both defaults should be true', () => {
        // Default behavior: new unavailability events block both PM and run assignment
        const defaultBlocksPm = true;
        const defaultBlocksRun = true;
        expect(defaultBlocksPm).toBe(true);
        expect(defaultBlocksRun).toBe(true);
      });
    });

    describe('Maximo Status Mapping', () => {
      test('COMP status should resolve event', () => {
        const maximoStatus = 'COMP';
        const isResolved = ['COMP', 'CLOSE', 'CAN'].includes(maximoStatus);
        expect(isResolved).toBe(true);
      });

      test('CLOSE status should resolve event', () => {
        const maximoStatus = 'CLOSE';
        const isResolved = ['COMP', 'CLOSE', 'CAN'].includes(maximoStatus);
        expect(isResolved).toBe(true);
      });

      test('CAN status should resolve event', () => {
        const maximoStatus = 'CAN';
        const isResolved = ['COMP', 'CLOSE', 'CAN'].includes(maximoStatus);
        expect(isResolved).toBe(true);
      });

      test('INPRG status should NOT resolve event', () => {
        const maximoStatus = 'INPRG';
        const isResolved = ['COMP', 'CLOSE', 'CAN'].includes(maximoStatus);
        expect(isResolved).toBe(false);
      });

      test('WAPPR status should NOT resolve event', () => {
        const maximoStatus = 'WAPPR';
        const isResolved = ['COMP', 'CLOSE', 'CAN'].includes(maximoStatus);
        expect(isResolved).toBe(false);
      });
    });

    describe('PM Conflict Severity', () => {
      test('GROUNDED restriction should be HIGH severity', () => {
        const restrictionLevel = 'GROUNDED';
        const severity = restrictionLevel === 'GROUNDED' ? 'HIGH' : 'MEDIUM';
        expect(severity).toBe('HIGH');
      });

      test('PM before estimated return should be HIGH severity', () => {
        const pmTargetDate = '2026-01-25';
        const estimatedReturn = '2026-02-01';
        const pmBeforeReturn = pmTargetDate < estimatedReturn;
        const severity = pmBeforeReturn ? 'HIGH' : 'MEDIUM';
        expect(severity).toBe('HIGH');
      });

      test('PM after estimated return should be MEDIUM severity', () => {
        const pmTargetDate = '2026-02-15';
        const estimatedReturn = '2026-02-01';
        const restrictionLevel = 'RESTRICTED' as 'RESTRICTED' | 'GROUNDED';
        const pmBeforeReturn = pmTargetDate < estimatedReturn;

        // Determine severity based on restriction level and timing
        let severity: 'HIGH' | 'MEDIUM' | 'LOW' = 'MEDIUM';
        if (restrictionLevel === 'GROUNDED') {
          severity = 'HIGH';
        } else if (pmBeforeReturn) {
          severity = 'HIGH';
        }
        expect(severity).toBe('MEDIUM');
      });
    });
  });

  describe('Optimizer Constraints Aggregation', () => {
    test('should aggregate unique train IDs by restriction level', () => {
      const events = [
        { trainId: 'train-1', restrictionLevel: 'GROUNDED', blocksPmScheduling: true, blocksRunAssignment: true },
        { trainId: 'train-1', restrictionLevel: 'GROUNDED', blocksPmScheduling: true, blocksRunAssignment: true },
        { trainId: 'train-2', restrictionLevel: 'RESTRICTED', blocksPmScheduling: true, blocksRunAssignment: false },
        { trainId: 'train-3', restrictionLevel: 'RESTRICTED', blocksPmScheduling: false, blocksRunAssignment: true },
      ];

      const groundedTrainIds = new Set<string>();
      const restrictedTrainIds = new Set<string>();
      const blockedFromPmTrainIds = new Set<string>();
      const blockedFromRunAssignmentTrainIds = new Set<string>();

      for (const event of events) {
        if (event.restrictionLevel === 'GROUNDED') {
          groundedTrainIds.add(event.trainId);
        } else {
          restrictedTrainIds.add(event.trainId);
        }
        if (event.blocksPmScheduling) {
          blockedFromPmTrainIds.add(event.trainId);
        }
        if (event.blocksRunAssignment) {
          blockedFromRunAssignmentTrainIds.add(event.trainId);
        }
      }

      // train-1 appears twice with GROUNDED, should be counted once
      expect(groundedTrainIds.size).toBe(1);
      expect(Array.from(groundedTrainIds)).toContain('train-1');

      // train-2 and train-3 are RESTRICTED
      expect(restrictedTrainIds.size).toBe(2);

      // train-1 and train-2 block PM scheduling
      expect(blockedFromPmTrainIds.size).toBe(2);

      // train-1 and train-3 block run assignment
      expect(blockedFromRunAssignmentTrainIds.size).toBe(2);
    });
  });

  describe('Error Handling', () => {
    test('NotFoundError should have correct properties for events', () => {
      const error = new NotFoundError('Unavailability event not found: event-123', {
        entityType: 'unavailability_event',
        entityId: 'event-123',
      });
      expect(error.statusCode).toBe(404);
      expect(error.entityType).toBe('unavailability_event');
    });

    test('TrainNotFoundError should work for unavailability', () => {
      const error = new TrainNotFoundError('train-123');
      expect(error.message).toContain('train-123');
      expect(error.code).toBe('BUS_011');
    });

    test('BusinessRuleError for already resolved event', () => {
      const error = new BusinessRuleError('Event is already resolved', {
        rule: 'event_already_resolved',
        context: { eventId: 'event-123' },
      });
      expect(error.rule).toBe('event_already_resolved');
      expect(error.statusCode).toBe(422);
    });

    test('ConflictError for duplicate external reference', () => {
      const error = new ConflictError(
        'Unavailability event already exists for MAXIMO reference WO-2026-001234'
      );
      expect(error.statusCode).toBe(409);
      expect(error.message).toContain('MAXIMO');
    });
  });

  describe('Date Calculations', () => {
    test('should detect PM within unavailability period', () => {
      const eventStart = new Date('2026-01-20');
      const estimatedReturn = new Date('2026-02-01');
      const pmTargetDate = new Date('2026-01-25');

      const pmDuringUnavailability =
        pmTargetDate >= eventStart && pmTargetDate <= estimatedReturn;
      expect(pmDuringUnavailability).toBe(true);
    });

    test('should detect PM after unavailability period', () => {
      const eventStart = new Date('2026-01-20');
      const estimatedReturn = new Date('2026-02-01');
      const pmTargetDate = new Date('2026-02-15');

      const pmDuringUnavailability =
        pmTargetDate >= eventStart && pmTargetDate <= estimatedReturn;
      expect(pmDuringUnavailability).toBe(false);
    });

    test('should handle no estimated return date', () => {
      const estimatedReturn = null as string | null;
      const pmTargetDate = '2026-01-25';

      // If no estimated return, assume indefinite unavailability
      let hasConflict = false;
      if (estimatedReturn === null) {
        hasConflict = true;
      } else {
        hasConflict = pmTargetDate < estimatedReturn;
      }
      expect(hasConflict).toBe(true);
    });
  });
});

